Infraestrutura como codigo para vault-secrets - HealthTech Systems - cost-optimization:

**main.tf:**
```hcl
terraform {
  required_providers {
    oci = {
      source  = "oracle/oci"
      version = "~> 5.0"
    }
  }
}

provider "oci" {
  region = "ap-mumbai-1"
}

resource "oci_vault-secrets" "main" {
  compartment_id = var.compartment_ocid
  display_name   = "vault-secrets-networking-005"

  # Configuracao especifica
  shape          = "VM.Standard3.Flex"

  tags = {
    project     = "HealthTech Systems - cost-optimization"
    environment = "networking"
    managed_by  = "terraform"
  }
}

variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment networking"
}

output "resource_id" {
  value = oci_vault-secrets.main.id
}
```

**variables.tf:**
```hcl
variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment"
}

variable "region" {
  type        = string
  default     = "ap-mumbai-1"
  description = "Regiao OCI"
}
```

**Deploy:**
```bash
terraform init
terraform plan -var="compartment_ocid=<ocid>"
terraform apply -var="compartment_ocid=<ocid>" -auto-approve
```

**Configuracao:**
- Compartment: `networking`
- Region: `ap-mumbai-1`
- Shape: `VM.Standard3.Flex`
- OCPUs: `32`
- Storage: `2000 GB`

Documentacao: https://docs.oracle.com/en-us/iaas/Content/KeyManagement/Concepts/keyoverview.htm

